  ('fire-eq-eng-moex-00653', 'fire-eq-eng', 'fire-eq-eng-moex-106-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '消防相關法規規定有關防焰物品之使用，下列何者敘述錯誤？', '["地面樓層達十一層以上建築物、地下建築物，其管理權人應使用附有防焰標示之地毯、窗簾、…等防 焰物品", "樓地板面積150平方公尺以上之身心障礙福利機構、身心障礙者職業訓練機構應使用防焰物品", "防焰物品或其材料非附有防焰標示，不得銷售及陳列", "所有防焰物品相關業者均須依規定申請防焰性能認證，應檢具經中央主管機關評鑑合格之試驗機構出 具之防焰性能試驗合格報告書"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "3f2a359fefc1", "answer_pdf_sha1": "3e5a201a58c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
